import React, { useContext } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertTriangle } from 'lucide-react';
import { AppContext } from '../App';

interface ConfirmModalProps {
  isOpen: boolean;
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
}

const ConfirmModal: React.FC<ConfirmModalProps> = ({ isOpen, message, onConfirm, onCancel }) => {
  const { t } = useContext(AppContext);

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center px-4">
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/50 backdrop-blur-sm"
            onClick={onCancel}
          />
          <motion.div 
            initial={{ scale: 0.9, opacity: 0 }} 
            animate={{ scale: 1, opacity: 1 }} 
            exit={{ scale: 0.9, opacity: 0 }}
            className="relative bg-white dark:bg-slate-800 rounded-xl shadow-2xl max-w-md w-full p-6 overflow-hidden transition-colors"
          >
             <div className="flex flex-col items-center text-center">
                <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center mb-4 text-amber-600 dark:text-amber-400">
                    <AlertTriangle size={24} />
                </div>
                <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">{t('confirm_title')}</h3>
                <p className="text-gray-600 dark:text-gray-400 mb-6">{message}</p>

                <div className="flex gap-3 w-full">
                    <button 
                        onClick={onCancel}
                        className="flex-1 py-2 px-4 bg-gray-100 dark:bg-slate-700 hover:bg-gray-200 dark:hover:bg-slate-600 text-gray-700 dark:text-slate-200 rounded-lg transition-colors"
                    >
                        {t('confirm_cancel')}
                    </button>
                    <button 
                        onClick={onConfirm}
                        className="flex-1 py-2 px-4 bg-red-600 hover:bg-red-700 text-white rounded-lg transition-colors"
                    >
                        {t('confirm_yes')}
                    </button>
                </div>
             </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default ConfirmModal;

import React, { useState, useEffect, useContext } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Trash2, Check } from 'lucide-react';
import { Teacher, LessonData } from '../types';
import { AppContext } from '../App';

interface EditModalProps {
  isOpen: boolean;
  initialData?: LessonData | null;
  teachers: Teacher[];
  onClose: () => void;
  onSave: (data: LessonData) => void;
  onDelete: () => void;
}

const EditModal: React.FC<EditModalProps> = ({ 
  isOpen, initialData, teachers, onClose, onSave, onDelete 
}) => {
  const { t } = useContext(AppContext);
  const [subject, setSubject] = useState('');
  const [teacherId, setTeacherId] = useState('');

  useEffect(() => {
    if (isOpen) {
      setSubject(initialData?.subject || '');
      setTeacherId(initialData?.teacherId || '');
    }
  }, [isOpen, initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (subject && teacherId) {
      onSave({ subject, teacherId });
      onClose();
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
            onClick={onClose}
          />
          <motion.div 
            initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 50, opacity: 0 }}
            className="relative bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-sm p-6 border border-slate-200 dark:border-slate-700 transition-colors"
          >
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-gray-800 dark:text-white">{t('edit_modal_title')}</h2>
              <button onClick={onClose} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('edit_modal_subject')}</label>
                <input 
                  type="text" 
                  value={subject}
                  onChange={(e) => setSubject(e.target.value)}
                  className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all dark:text-white"
                  placeholder={t('edit_modal_placeholder')}
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('edit_modal_teacher')}</label>
                <select 
                  value={teacherId}
                  onChange={(e) => setTeacherId(e.target.value)}
                  className="w-full px-4 py-2 bg-white dark:bg-slate-900 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all dark:text-white"
                >
                  <option value="">{t('edit_modal_teacher')}</option>
                  {teachers.map(t_item => (
                    <option key={t_item.id} value={t_item.id}>{t_item.name}</option>
                  ))}
                </select>
              </div>

              <div className="flex gap-3 pt-4">
                {initialData && (
                  <button 
                    type="button"
                    onClick={onDelete}
                    className="p-2 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                    title={t('confirm_cancel')}
                  >
                    <Trash2 size={20} />
                  </button>
                )}
                <button 
                  type="submit"
                  disabled={!subject || !teacherId}
                  className="flex-1 flex items-center justify-center gap-2 bg-primary-600 hover:bg-primary-700 text-white py-2 px-4 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-bold"
                >
                  <Check size={18} />
                  <span>{t('edit_modal_save')}</span>
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default EditModal;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { Plus, Trash2, Edit2, Check, X, Palette, Shuffle } from 'lucide-react';
import { generateId } from '../utils';
import { COLORS } from '../types';
import ConfirmModal from './ConfirmModal';

const Teachers: React.FC = () => {
  const { state, dispatch, addToast, t } = useContext(AppContext);
  const [newTeacherName, setNewTeacherName] = useState('');
  const [colorMode, setColorMode] = useState<'random' | 'custom'>('random');
  const [customColor, setCustomColor] = useState('#3b82f6');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName.trim()) return;
    const color = colorMode === 'random' ? COLORS[Math.floor(Math.random() * COLORS.length)] : customColor;
    dispatch({ type: 'ADD_TEACHER', payload: { id: generateId(), name: newTeacherName, color } });
    setNewTeacherName('');
    addToast('success', t('toast_teacher_added'));
  };

  const startEdit = (t_item: any) => {
    setEditingId(t_item.id);
    setEditName(t_item.name);
  };

  const saveEdit = (t_item: any) => {
    dispatch({ type: 'UPDATE_TEACHER', payload: { ...t_item, name: editName } });
    setEditingId(null);
    addToast('success', t('toast_updated'));
  };

  const confirmDelete = () => {
    if (deleteId) {
        dispatch({ type: 'DELETE_TEACHER', payload: deleteId });
        addToast('success', t('toast_deleted'));
        setDeleteId(null);
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in duration-500">
      <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-6">{t('teacher_mgmt_title')}</h2>

      <form onSubmit={handleAdd} className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-200 dark:border-slate-700 mb-8 transition-colors">
        <div className="flex flex-col gap-6">
            <div className="flex gap-4">
                <input 
                type="text" 
                value={newTeacherName}
                onChange={(e) => setNewTeacherName(e.target.value)}
                placeholder={t('teacher_name_placeholder')}
                className="flex-1 px-6 py-4 bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-2xl focus:ring-2 focus:ring-primary-500 outline-none dark:text-white transition-all font-bold"
                />
                <button 
                    type="submit"
                    disabled={!newTeacherName.trim()}
                    className="bg-primary-600 hover:bg-primary-700 text-white px-8 rounded-2xl flex items-center gap-2 disabled:opacity-50 transition-all whitespace-nowrap font-black shadow-lg shadow-primary-500/20"
                >
                    <Plus size={20} />
                    <span>{t('teacher_add_btn')}</span>
                </button>
            </div>

            <div className="flex items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-2xl transition-colors border dark:border-slate-700">
                <span className="text-sm font-black text-slate-600 dark:text-slate-400">{t('teacher_color_mode')}:</span>
                <div className="flex gap-2">
                    <button
                        type="button"
                        onClick={() => setColorMode('random')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                            colorMode === 'random' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-md' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Shuffle size={16} />
                        <span>{t('teacher_color_random')}</span>
                    </button>
                    <button
                        type="button"
                        onClick={() => setColorMode('custom')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold transition-all border ${
                            colorMode === 'custom' 
                            ? 'bg-white dark:bg-slate-800 border-primary-500 text-primary-600 dark:text-primary-400 shadow-md' 
                            : 'bg-transparent border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800'
                        }`}
                    >
                        <Palette size={16} />
                        <span>{t('teacher_color_custom')}</span>
                    </button>
                </div>
                {colorMode === 'custom' && (
                    <div className="flex items-center gap-2 animate-in slide-in-from-right-4 duration-300">
                        <input type="color" value={customColor} onChange={(e) => setCustomColor(e.target.value)} className="w-10 h-10 rounded-xl cursor-pointer border-2 border-white dark:border-slate-700 shadow-md" />
                    </div>
                )}
            </div>
        </div>
      </form>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {state.teachers.map(t_item => (
            <div key={t_item.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-center justify-between group transition-all hover:shadow-md">
                {editingId === t_item.id ? (
                    <div className="flex items-center gap-2 w-full">
                        <input type="text" value={editName} onChange={(e) => setEditName(e.target.value)} className="flex-1 px-3 py-2 border dark:border-slate-600 rounded-xl bg-slate-50 dark:bg-slate-900 dark:text-white font-bold" autoFocus />
                        <button onClick={() => saveEdit(t_item)} className="text-green-600 p-2 bg-green-50 dark:bg-green-900/20 rounded-xl hover:bg-green-100"><Check size={20} /></button>
                    </div>
                ) : (
                    <>
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black shadow-lg border-2 border-white dark:border-slate-700 text-xl" style={{ backgroundColor: t_item.color }}>
                                {t_item.name.charAt(0)}
                            </div>
                            <span className="font-black text-slate-800 dark:text-slate-200">{t_item.name}</span>
                        </div>
                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => startEdit(t_item)} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl"><Edit2 size={20} /></button>
                            <button onClick={() => setDeleteId(t_item.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl"><Trash2 size={20} /></button>
                        </div>
                    </>
                )}
            </div>
        ))}
      </div>
      <ConfirmModal isOpen={!!deleteId} message={t('teacher_confirm_delete')} onCancel={() => setDeleteId(null)} onConfirm={confirmDelete} />
    </div>
  );
};

export default Teachers;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { Save } from 'lucide-react';
import { CellDesign } from '../types';

const DesignPage: React.FC = () => {
  const { state, dispatch, addToast, t } = useContext(AppContext);
  const isDarkMode = state.ui.theme === 'dark' || (state.ui.theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  // Deep copy to avoid reference issues during edit
  const [design, setDesign] = useState(JSON.parse(JSON.stringify(state.design)));

  const updateField = (type: 'lesson' | 'break', field: keyof CellDesign, value: any) => {
    setDesign((prev: any) => ({
        ...prev,
        [type]: { ...prev[type], [field]: value }
    }));
  };

  const handleSave = () => {
    dispatch({ type: 'UPDATE_DESIGN', payload: design });
    addToast('success', t('toast_settings_saved'));
  };

  const renderControls = (type: 'lesson' | 'break', label: string) => {
    // Adaptive background for preview if using default white
    let previewBg = design[type].backgroundColor;
    if (isDarkMode && (previewBg === '#ffffff' || previewBg === 'white' || previewBg.toLowerCase() === '#fff')) {
        previewBg = type === 'break' ? '#1e293b' : '#0f172a';
    }

    return (
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 transition-colors">
            <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-4 pb-2 border-b border-slate-100 dark:border-slate-700">{label}</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_bg_color')}</label>
                    <div className="flex gap-2">
                        <input type="color" className="w-10 h-10 rounded cursor-pointer dark:bg-slate-900 border-none" value={design[type].backgroundColor} onChange={(e) => updateField(type, 'backgroundColor', e.target.value)} />
                        <input type="text" className="flex-1 border dark:border-slate-600 rounded px-2 text-sm bg-white dark:bg-slate-900 dark:text-white" value={design[type].backgroundColor} onChange={(e) => updateField(type, 'backgroundColor', e.target.value)} />
                    </div>
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_border_color')}</label>
                    <div className="flex gap-2">
                        <input type="color" className="w-10 h-10 rounded cursor-pointer dark:bg-slate-900 border-none" value={design[type].borderColor} onChange={(e) => updateField(type, 'borderColor', e.target.value)} />
                        <input type="text" className="flex-1 border dark:border-slate-600 rounded px-2 text-sm bg-white dark:bg-slate-900 dark:text-white" value={design[type].borderColor} onChange={(e) => updateField(type, 'borderColor', e.target.value)} />
                    </div>
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_border_width')} ({design[type].borderWidth}px)</label>
                    <input type="range" min="0" max="5" className="w-full accent-primary-500" value={design[type].borderWidth} onChange={(e) => updateField(type, 'borderWidth', parseInt(e.target.value))} />
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_border_radius')} ({design[type].borderRadius}px)</label>
                    <input type="range" min="0" max="20" className="w-full accent-primary-500" value={design[type].borderRadius} onChange={(e) => updateField(type, 'borderRadius', parseInt(e.target.value))} />
                </div>

                <div>
                    <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_margin')} ({design[type].margin}px)</label>
                    <input type="range" min="0" max="10" className="w-full accent-primary-500" value={design[type].margin} onChange={(e) => updateField(type, 'margin', parseInt(e.target.value))} />
                </div>

                {type === 'lesson' && (
                    <div>
                        <label className="text-xs font-bold text-slate-500 dark:text-slate-400 block mb-1">{t('design_font_size')} ({design[type].fontSize}px)</label>
                        <input type="range" min="10" max="20" className="w-full accent-primary-500" value={design[type].fontSize} onChange={(e) => updateField(type, 'fontSize', parseInt(e.target.value))} />
                    </div>
                )}

            </div>

            {/* Preview */}
            <div className="mt-6 p-4 bg-slate-100 dark:bg-slate-900/50 rounded-lg flex justify-center transition-colors">
                <div style={{
                    width: '140px', height: '80px',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    backgroundColor: previewBg,
                    borderColor: design[type].borderColor,
                    borderWidth: `${design[type].borderWidth}px`,
                    borderStyle: design[type].borderStyle,
                    borderRadius: `${design[type].borderRadius}px`,
                    margin: 0, // Margin handled by container in preview
                    fontSize: `${design[type].fontSize}px`,
                    boxShadow: design[type].shadow === 'none' ? 'none' : 'inset 0 2px 4px 0 rgb(0 0 0 / 0.05)',
                    color: isDarkMode && (previewBg === '#1e293b' || previewBg === '#0f172a') ? '#f1f5f9' : '#000'
                }}>
                    <span>{t('design_preview_text')}</span>
                </div>
            </div>
        </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">{t('design_title')}</h2>
        <button 
            onClick={handleSave}
            className="bg-primary-600 hover:bg-primary-700 text-white px-6 py-2 rounded-xl flex items-center gap-2 shadow-lg transition-colors"
        >
            <Save size={20} />
            <span>{t('edit_modal_save')}</span>
        </button>
      </div>

      <div className="grid gap-6">
        {renderControls('lesson', t('design_lesson_style'))}
        {renderControls('break', t('design_break_style'))}
      </div>
    </div>
  );
};

export default DesignPage;

import React, { useContext, useRef, useState } from 'react';
import { AppContext } from '../App';
import { Download, Upload, Printer, AlertCircle, Eye, Share2 } from 'lucide-react';
import ConfirmModal from './ConfirmModal';

interface Props {
  setPage: (page: string) => void;
}

const ExportPage: React.FC<Props> = ({ setPage }) => {
  const { state, dispatch, addToast, t } = useContext(AppContext);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [pendingData, setPendingData] = useState<any>(null);

  const handleExportJSON = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state));
    const date = new Date();
    const dateStr = date.getFullYear() + 
                    String(date.getMonth() + 1).padStart(2, '0') + 
                    String(date.getDate()).padStart(2, '0');
    const filename = `timetable_backup_${dateStr}.json`;

    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", filename);
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
    addToast('success', t('toast_settings_saved'));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const json = JSON.parse(event.target?.result as string);
            if (json && typeof json === 'object') {
                setPendingData(json);
                setIsImporting(true);
            }
        } catch (err) { addToast('error', t('toast_error')); }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const confirmImport = () => {
    if (pendingData) {
        dispatch({ type: 'INIT', payload: pendingData });
        addToast('success', t('toast_import_success'));
        setIsImporting(false);
        setPendingData(null);
    }
  };

  return (
    <div className="max-w-4xl mx-auto pb-20">
      <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-6">{t('menu_export')}</h2>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* JSON Section */}
        <div className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-200 dark:border-slate-700 flex flex-col transition-colors">
            <div className="bg-blue-500/10 w-14 h-14 rounded-2xl flex items-center justify-center text-blue-600 mb-6">
                <Share2 size={30} />
            </div>
            <h3 className="font-bold text-xl mb-3 dark:text-white">{t('export_backup_title')}</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8 leading-relaxed">
                {t('export_backup_desc')}
            </p>
            <div className="space-y-3 mt-auto">
                <button 
                    onClick={handleExportJSON}
                    className="w-full py-4 bg-slate-100 dark:bg-slate-900 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-2xl flex items-center justify-center gap-2 font-bold transition-all"
                >
                    <Download size={20} />
                    <span>{t('export_json_btn')}</span>
                </button>
                <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-blue-500/20 transition-all"
                >
                    <Upload size={20} />
                    <span>{t('export_import_btn')}</span>
                </button>
                <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileChange} />
            </div>
        </div>

        {/* PDF Section */}
        <div className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-200 dark:border-slate-700 flex flex-col transition-colors">
            <div className="bg-primary-500/10 w-14 h-14 rounded-2xl flex items-center justify-center text-primary-600 mb-6">
                <Printer size={30} />
            </div>
            <h3 className="font-bold text-xl mb-3 dark:text-white">{t('export_print_studio_title')}</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8 leading-relaxed">
                {t('export_print_studio_desc')}
            </p>
            <button 
                onClick={() => setPage('print-preview')}
                className="w-full py-4 bg-primary-600 hover:bg-primary-700 text-white rounded-2xl flex items-center justify-center gap-2 font-bold shadow-lg shadow-primary-500/20 mt-auto transition-all"
            >
                <Eye size={20} />
                <span>{t('export_print_studio_btn')}</span>
            </button>
        </div>

      </div>

      <div className="mt-8 bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-800 p-5 rounded-3xl flex items-start gap-4">
          <AlertCircle className="text-amber-600 shrink-0 mt-1" size={20} />
          <p className="text-sm text-amber-800 dark:text-amber-300 leading-relaxed">
              <strong>{t('export_note')}</strong> {t('export_note_text')}
          </p>
      </div>

      <ConfirmModal 
        isOpen={isImporting}
        message={t('export_import_confirm')}
        onCancel={() => { setIsImporting(false); setPendingData(null); }}
        onConfirm={confirmImport}
      />
    </div>
  );
};

export default ExportPage;

import React, { useContext } from 'react';
import { AppState } from '../types';
import { calculateTimeSlots, getContrastColor } from '../utils';
import { Coffee } from 'lucide-react';
import { AppContext } from '../App';

interface Props {
  state: AppState;
  previewMode?: boolean;
}

const TimetableTemplate: React.FC<Props> = ({ state, previewMode = false }) => {
  const { t } = useContext(AppContext);
  const { teachers, classes, schedule, settings, design, printDesign } = state;
  const slots = calculateTimeSlots(settings);
  const getTeacher = (id: string) => teachers.find(t_item => t_item.id === id);

  // Destructure Pro styling options
  const {
      teacherDisplayMode = 'badge',
      fontSizeTitle = 32,
      fontSizeSubtitle = 18,
      fontSizeHeader = 14,
      fontSizeSubject = 14,
      fontSizeTeacher = 11,
      cellMinHeight = 90,
      cellVerticalAlign = 'center',
      cellGap = 6,
      cellPadding = 4
  } = printDesign;

  // Theme Engine
  const getThemeStyles = () => {
    const base = {
      gridBorder: '#e2e8f0',
      oddRow: '#ffffff',
      evenRow: '#f8fafc',
      headerBg: '#1e293b',
      headerText: '#ffffff',
      font: 'Vazirmatn, sans-serif',
      breakBg: '#fff7ed',
      breakText: '#ea580c',
    };

    switch (printDesign.theme) {
      case 'modern':
        return { ...base, headerBg: printDesign.primaryColor, oddRow: '#f8fafc', evenRow: '#ffffff', breakBg: '#f1f5f9', breakText: '#64748b' };
      case 'minimal':
        return { ...base, headerBg: '#ffffff', headerText: '#1e293b', gridBorder: '#000000', evenRow: '#ffffff', oddRow: '#ffffff', breakBg: '#ffffff', breakText: '#94a3b8' };
      case 'colorful':
        return { ...base, headerBg: '#3b82f6', headerText: '#ffffff', gridBorder: '#ffffff', oddRow: '#eff6ff', evenRow: '#dbeafe', breakBg: '#fef3c7', breakText: '#d97706' };
      case 'corporate':
        return { ...base, headerBg: '#334155', headerText: '#ffffff', gridBorder: '#94a3b8', oddRow: '#f1f5f9', evenRow: '#cbd5e1', breakBg: '#e2e8f0', breakText: '#475569' };
      default: // classic
        return base;
    }
  };

  const theme = getThemeStyles();

  // Header Style Logic
  let hBg = theme.headerBg;
  let hText = theme.headerText;
  let hBorder = theme.gridBorder;

  if (printDesign.headerStyle === 'outline') {
    hBg = 'transparent';
    hText = printDesign.primaryColor;
    hBorder = printDesign.primaryColor;
  } else if (printDesign.headerStyle === 'simple') {
    hBg = 'transparent';
    hText = '#000';
  }

  const justifyContentMap = {
      start: 'flex-start',
      center: 'center',
      end: 'flex-end'
  };

  return (
    <div 
      className="w-full bg-white text-right relative overflow-hidden" 
      dir={printDesign.direction}
      style={{ 
        fontFamily: theme.font,
        padding: previewMode ? `${printDesign.paddingY}px ${printDesign.paddingX}px` : '40px',
        transform: `scale(${printDesign.scale / 100})`,
        transformOrigin: 'top center',
        minHeight: '100%'
      }}
    >
      {/* Watermark */}
      {printDesign.showWatermark && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0 opacity-[0.08]">
            <h1 className="text-[150px] font-black text-slate-900 -rotate-45 whitespace-nowrap">
                {printDesign.watermarkText}
            </h1>
        </div>
      )}

      {/* Header */}
      <div className="relative z-10 flex justify-between items-end mb-8 border-b-4 pb-4" style={{ borderColor: printDesign.primaryColor }}>
        <div>
          <h1 className="text-slate-900 mb-2" style={{ 
              fontSize: `${fontSizeTitle}px`,
              fontWeight: printDesign.fontStyle === 'bold' ? 900 : 700 
          }}>
            {printDesign.title}
          </h1>
          <p className="text-slate-500" style={{ fontSize: `${fontSizeSubtitle}px` }}>{printDesign.subtitle}</p>
        </div>
        <div className="text-left opacity-75">
          <div className="text-sm text-slate-500">{t('print_date')}: {new Date().toLocaleDateString(printDesign.direction === 'rtl' ? 'fa-IR' : 'en-US')}</div>
          <div className="font-bold text-slate-800 text-lg">Smart Timetable</div>
        </div>
      </div>

      {/* Grid */}
      <div 
        className="relative z-10 rounded-lg overflow-hidden"
        style={{ 
            border: `1px solid ${theme.gridBorder}`,
            boxShadow: previewMode ? 'none' : '0 4px 6px -1px rgba(0, 0, 0, 0.1)' 
        }}
      >
        <div className="grid" style={{ gridTemplateColumns: `160px repeat(${slots.length}, 1fr)` }}>

            <div 
                className="p-3 font-bold flex items-center justify-center border-b border-l"
                style={{ 
                    backgroundColor: hBg, 
                    color: hText, 
                    borderColor: hBorder,
                    fontSize: `${fontSizeHeader}px`
                }}
            >
                {t('grid_class_time')}
            </div>

            {slots.map(slot => (
                <div 
                    key={slot.id} 
                    className="p-2 text-center border-b border-l flex flex-col items-center justify-center"
                    style={{ 
                        backgroundColor: slot.type === 'break' ? theme.breakBg : hBg, 
                        color: slot.type === 'break' ? theme.breakText : hText,
                        borderColor: hBorder 
                    }}
                >
                    {slot.type === 'break' ? (
                         <div className="flex flex-col items-center gap-1">
                             <Coffee size={fontSizeHeader + 4} />
                             <span className="font-bold" style={{ fontSize: `${fontSizeHeader}px` }}>{slot.label === 'دمه' ? t('grid_break') : slot.label}</span>
                         </div>
                    ) : (
                        <>
                            <span className="font-bold" style={{ fontSize: `${fontSizeHeader}px` }}>{slot.label.replace('ګړۍ', t('grid_lesson_unit')).replace('Period', t('grid_lesson_unit'))}</span>
                            {printDesign.showTimes && (
                                <span className="opacity-80 mt-1 font-mono dir-ltr" style={{ fontSize: `${Math.max(10, fontSizeHeader - 4)}px` }}>{slot.start} - {slot.end}</span>
                            )}
                        </>
                    )}
                </div>
            ))}

            {classes.map((cls, idx) => (
                <React.Fragment key={cls.id}>
                    <div 
                        className="p-3 font-bold border-b border-l flex items-center justify-center"
                        style={{ 
                            backgroundColor: idx % 2 === 0 ? theme.evenRow : theme.oddRow,
                            color: '#1e293b',
                            borderColor: theme.gridBorder,
                            fontSize: `${fontSizeHeader}px`
                        }}
                    >
                        {cls.name}
                    </div>

                    {slots.map(slot => {
                        const key = `${cls.id}_${slot.id}`;
                        const lesson = schedule[key];
                        const teacher = lesson ? getTeacher(lesson.teacherId) : null;

                        if (slot.type === 'break') {
                            return (
                                <div 
                                    key={key} 
                                    className="border-b border-l flex flex-col items-center justify-center opacity-80"
                                    style={{ 
                                        backgroundColor: theme.breakBg,
                                        borderColor: theme.gridBorder,
                                        color: theme.breakText,
                                        minHeight: `${cellMinHeight}px`
                                    }}
                                >
                                    <Coffee size={24} strokeWidth={1.5} className="opacity-50" />
                                    <span className="text-[10px] font-bold opacity-50 mt-1">{t('grid_break')}</span>
                                </div>
                            );
                        }

                        return (
                            <div 
                                key={key} 
                                className="border-b border-l relative"
                                style={{ 
                                    backgroundColor: idx % 2 === 0 ? theme.evenRow : theme.oddRow,
                                    borderColor: theme.gridBorder,
                                    minHeight: `${cellMinHeight}px`,
                                    padding: `${cellPadding}px`
                                }}
                            >
                                {lesson ? (
                                    <div 
                                        className="w-full h-full rounded flex flex-col overflow-hidden"
                                        style={{
                                            backgroundColor: design.lesson.backgroundColor,
                                            border: `${design.lesson.borderWidth}px ${design.lesson.borderStyle} ${design.lesson.borderColor}`,
                                            borderRadius: `${design.lesson.borderRadius}px`,
                                            justifyContent: justifyContentMap[cellVerticalAlign],
                                            alignItems: 'center',
                                            gap: `${cellGap}px`
                                        }}
                                    >
                                        <div 
                                            className="font-bold text-slate-900 leading-tight text-center w-full break-words"
                                            style={{ fontSize: `${fontSizeSubject}px` }}
                                        >
                                            {lesson.subject}
                                        </div>

                                        {teacher && teacherDisplayMode !== 'hidden' && (
                                            <>
                                                {teacherDisplayMode === 'badge' && (
                                                    <div 
                                                        className="px-2 py-0.5 rounded-full font-bold max-w-[95%] truncate text-center"
                                                        style={{
                                                            fontSize: `${fontSizeTeacher}px`,
                                                            backgroundColor: teacher.color,
                                                            color: getContrastColor(teacher.color)
                                                        }}
                                                    >
                                                        {teacher.name}
                                                    </div>
                                                )}

                                                {teacherDisplayMode === 'text' && (
                                                    <div 
                                                        className="font-medium truncate w-full px-1 text-center"
                                                        style={{
                                                            fontSize: `${fontSizeTeacher}px`,
                                                            color: teacher.color
                                                        }}
                                                    >
                                                        {teacher.name}
                                                    </div>
                                                )}

                                                {teacherDisplayMode === 'dot' && (
                                                    <div 
                                                        className="w-3 h-3 rounded-full"
                                                        style={{ backgroundColor: teacher.color }}
                                                        title={teacher.name}
                                                    />
                                                )}
                                            </>
                                        )}
                                    </div>
                                ) : null}
                            </div>
                        );
                    })}
                </React.Fragment>
            ))}
        </div>
      </div>

      {/* Footer */}
      <div className="mt-8">
        {printDesign.showLegend && (
            <div className="flex flex-wrap gap-4 justify-center mb-6">
                {teachers.map(t_item => (
                    <div key={t_item.id} className="flex items-center gap-2 px-3 py-1.5 rounded-full border bg-white shadow-sm" style={{ borderColor: theme.gridBorder }}>
                        <div className="w-5 h-5 rounded-full shadow-inner" style={{ backgroundColor: t_item.color }}></div>
                        <span className="text-sm font-bold text-slate-700">{t_item.name}</span>
                    </div>
                ))}
            </div>
        )}

        {printDesign.showFooter && (
            <div className="border-t pt-4 flex justify-between items-center text-sm text-slate-500" style={{ borderColor: theme.gridBorder }}>
                <div>{printDesign.footerText}</div>
                <div>{t('print_page_x_of_y')}</div>
            </div>
        )}
      </div>

    </div>
  );
};

export default TimetableTemplate;

import React, { useContext, useState } from 'react';
import { AppContext } from '../App';
import { ArrowRight, Download, Layout, Type, Palette, Printer, Stamp, Eye, Grid, AlignVerticalSpaceAround, MoveVertical, ChevronLeft, ChevronRight, Settings2, Maximize2, Minimize2, X } from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import TimetableTemplate from './TimetableTemplate';

interface Props {
  onBack: () => void;
}

type TabType = 'layout' | 'content' | 'style' | 'extras';

const PrintPreviewPage: React.FC<Props> = ({ onBack }) => {
  const { state, dispatch, addToast, t } = useContext(AppContext);
  const { printDesign } = state;
  const [activeTab, setActiveTab] = useState<TabType>('layout');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isFullScreen, setIsFullScreen] = useState(false);

  const updateDesign = (key: keyof typeof printDesign, value: any) => {
    dispatch({ type: 'UPDATE_PRINT_DESIGN', payload: { [key]: value } });
  };

  const handleDownload = async () => {
    const element = document.getElementById('export-canvas-container');
    if (!element) return;

    addToast('info', t('toast_pro_download'));

    try {
        await new Promise(r => setTimeout(r, 500));

        const canvas = await html2canvas(element, {
            scale: 3,
            useCORS: true,
            logging: false,
            backgroundColor: '#ffffff',
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const pdf = new jsPDF({
            orientation: 'landscape',
            unit: 'mm',
            format: 'a4'
        });

        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const imgProps = pdf.getImageProperties(imgData);
        const ratio = imgProps.width / imgProps.height;

        let renderWidth = pdfWidth;
        let renderHeight = pdfWidth / ratio;

        if (renderHeight > pdfHeight) {
             renderHeight = pdfHeight;
             renderWidth = pdfHeight * ratio;
        }

        const x = (pdfWidth - renderWidth) / 2;
        const y = (pdfHeight - renderHeight) / 2;

        pdf.addImage(imgData, 'JPEG', x, y, renderWidth, renderHeight);

        const date = new Date();
        const dateStr = date.getFullYear() + 
                        String(date.getMonth() + 1).padStart(2, '0') + 
                        String(date.getDate()).padStart(2, '0');

        pdf.save(`timetable_pro_${dateStr}.pdf`);
        addToast('success', t('toast_pdf_success'));

    } catch (e) {
        console.error(e);
        addToast('error', t('toast_error'));
    }
  };

  const TabButton = ({ id, label, icon }: { id: TabType, label: string, icon: React.ReactNode }) => (
    <button 
        onClick={() => setActiveTab(id)}
        className={`flex-1 py-3 flex flex-col items-center justify-center gap-1 text-xs font-medium transition-all border-b-2 ${
            activeTab === id 
            ? 'border-indigo-600 text-indigo-700 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30' 
            : 'border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-800'
        }`}
    >
        {icon}
        <span>{label}</span>
    </button>
  );

  return (
    <div className="h-full flex flex-col bg-slate-100 dark:bg-slate-950 transition-colors duration-300">
      {!isFullScreen && (
          <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 md:px-6 py-3 flex justify-between items-center shadow-sm z-20 flex-shrink-0 transition-colors">
            <div className="flex items-center gap-4">
                <button onClick={onBack} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors text-slate-600 dark:text-slate-400" title={t('confirm_cancel')}>
                    <ArrowRight size={24} />
                </button>
                <div className="flex items-center gap-3">
                    <h2 className="text-lg font-bold text-slate-800 dark:text-white hidden md:block">{t('print_studio_title')}</h2>
                    <span className="bg-indigo-100 dark:bg-indigo-900 text-indigo-700 dark:text-indigo-400 text-[10px] px-2 py-0.5 rounded-full font-bold">PRO</span>

                    {!isSidebarOpen && (
                        <button 
                            onClick={() => setIsSidebarOpen(true)}
                            className="flex items-center gap-2 text-sm text-indigo-600 dark:text-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 px-3 py-1.5 rounded-lg border border-indigo-100 dark:border-indigo-900 transition-colors"
                        >
                            <Settings2 size={16} />
                            <span>{t('print_btn_settings')}</span>
                        </button>
                    )}
                </div>
            </div>
            <div className="flex gap-3">
                <button onClick={() => setIsFullScreen(true)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-slate-600 dark:text-slate-400 transition-colors" title={t('dashboard_fullscreen')}>
                    <Maximize2 size={20} />
                </button>
                <button onClick={() => window.print()} className="px-3 md:px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg flex items-center gap-2 font-medium transition-colors text-sm">
                    <Printer size={18} />
                    <span className="hidden md:inline">{t('print_btn_print')}</span>
                </button>
                <button onClick={handleDownload} className="px-4 md:px-5 py-2 bg-indigo-600 dark:bg-indigo-500 text-white hover:bg-indigo-700 dark:hover:bg-indigo-600 rounded-lg flex items-center gap-2 shadow-lg shadow-indigo-200 dark:shadow-none font-bold transition-colors text-sm">
                    <Download size={18} />
                    <span className="hidden md:inline">{t('print_btn_download')}</span>
                </button>
            </div>
          </div>
      )}

      <div className="flex-1 overflow-hidden flex relative">
        {!isFullScreen && (
            <div className={`bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 flex flex-col shadow-xl z-10 transition-all duration-300 ease-in-out absolute inset-y-0 right-0 md:static ${isSidebarOpen ? 'w-80 translate-x-0' : 'w-0 translate-x-full opacity-0 md:opacity-100 md:w-0 md:translate-x-0 overflow-hidden'}`}>
                <button onClick={() => setIsSidebarOpen(false)} className="absolute top-1/2 -left-3 z-50 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-md rounded-full p-1 text-slate-500 hover:text-indigo-600 hidden md:block">
                    <ChevronRight size={16} />
                </button>

                <div className="flex border-b border-slate-200 dark:border-slate-800">
                    <TabButton id="layout" label={t('print_tab_layout')} icon={<Layout size={18} />} />
                    <TabButton id="content" label={t('print_tab_content')} icon={<Type size={18} />} />
                    <TabButton id="style" label={t('print_tab_style')} icon={<Palette size={18} />} />
                    <TabButton id="extras" label={t('print_tab_extras')} icon={<Stamp size={18} />} />
